package org.apache.commons.math3.optim.nonlinear.vector.jacobian;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math3.optim.nonlinear.vector.jacobian.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.optim.nonlinear.vector.jacobian.steps;

import io.cucumber.java.en.*;
import org.apache.commons.math3.linear.DiagonalMatrix;
import org.apache.commons.math3.linear.RealMatrix;
import org.apache.commons.math3.fitting.PolynomialFitter;
import org.apache.commons.math3.optim.nonlinear.vector.jacobian.LevenbergMarquardtOptimizer;
import org.apache.commons.math3.fitting.WeightedObservedPoint;

import static org.junit.Assert.*;

public class StepDefs {
    private DiagonalMatrix weightMatrix;
    private RealMatrix sqrtMatrix;
    private PolynomialFitter polynomialFitter;
    private WeightedObservedPoint[] observedPoints;
    private boolean outOfMemoryErrorThrown = false;

    @Given("a weight matrix that is an instance of DiagonalMatrix")
    public void a_weight_matrix_that_is_an_instance_of_DiagonalMatrix() {
        weightMatrix = new DiagonalMatrix(100); // Initialize with 100 for basic test
        for (int i = 0; i < 100; i++) {
            weightMatrix.setEntry(i, i, 4.0); // Set diagonal values to 4
        }
    }

    @And("the matrix has a large dimension \\(e.g., {int} rows)")
    public void the_matrix_has_a_large_dimension_e_g_rows(Integer dimension) {
        // Reinitialize with large dimension to trigger OOM
        weightMatrix = new DiagonalMatrix(dimension);
        for (int i = 0; i < dimension; i++) {
            weightMatrix.setEntry(i, i, 4.0); // Set diagonal values to 4
        }
    }

    @When("the optimizer computes the square root of the weight matrix")
    public void the_optimizer_computes_the_square_root_of_the_weight_matrix() {
        try {
            // In the original bug, computing square root would trigger eigen decomposition
            // causing OutOfMemoryError for large diagonal matrices
            sqrtMatrix = weightMatrix.getSquareRoot();
        } catch (OutOfMemoryError e) {
            outOfMemoryErrorThrown = true;
        }
    }

    @Then("it should identify that the matrix is diagonal")
    public void it_should_identify_that_the_matrix_is_diagonal() {
        // The fix should recognize DiagonalMatrix and handle it efficiently
        assertNotNull("The weight matrix should be initialized", weightMatrix);
    }

    @And("it should compute the square root by taking the square root of the diagonal elements")
    public void it_should_compute_the_square_root_by_taking_the_square_root_of_the_diagonal_elements() {
        if (sqrtMatrix != null) {
            assertTrue("The square root matrix should be computed without OOM", !outOfMemoryErrorThrown);
        }
    }

    @And("it should NOT perform a full EigenDecomposition")
    public void it_should_NOT_perform_a_full_EigenDecomposition() {
        // This step tests the performance/implementation - if the bug exists,
        // this will fail by causing OOM during eigen decomposition
        assertTrue("The implementation should avoid full eigen decomposition for diagonal matrices", !outOfMemoryErrorThrown);
    }

    @And("the memory usage should be proportional to the diagonal size \\(O\\(N\\)\\), not the square of the dimension \\(O\\(N^2\\)\\)")
    public void the_memory_usage_should_be_proportional_to_the_diagonal_size_O_N_not_the_square_of_the_dimension_O_N_2() {
        assertTrue("Memory usage should be efficient, without OOM error", !outOfMemoryErrorThrown);
    }

    @Given("a PolynomialFitter is used with a LevenbergMarquardtOptimizer")
    public void a_PolynomialFitter_is_used_with_a_LevenbergMarquardtOptimizer() {
        LevenbergMarquardtOptimizer optimizer = new LevenbergMarquardtOptimizer();
        polynomialFitter = new PolynomialFitter(optimizer);
    }

    @And("{int} observed points are added to the fitter")
    public void observed_points_are_added_to_the_fitter(Integer pointCount) {
        observedPoints = new WeightedObservedPoint[pointCount];
        for (int i = 0; i < pointCount; i++) {
            observedPoints[i] = new WeightedObservedPoint(1.0, i, i * i); // Simple quadratic
        }

        for (WeightedObservedPoint point : observedPoints) {
            polynomialFitter.addObservedPoint(point);
        }
    }

    @When("the fit method is called")
    public void the_fit_method_is_called() {
        try {
            // This should cause OOM in the buggy version due to large weight matrix handling
            polynomialFitter.fit(2); // Fit with a 2nd degree polynomial
        } catch (OutOfMemoryError e) {
            outOfMemoryErrorThrown = true;
        }
    }

    @Then("the optimization should complete successfully")
    public void the_optimization_should_complete_successfully() {
        assertTrue("Optimization should complete without OOM in the fixed version", !outOfMemoryErrorThrown);
    }

    @And("it should not throw a java.lang.OutOfMemoryError: Java heap space")
    public void it_should_not_throw_a_java_lang_OutOfMemoryError_Java_heap_space() {
        assertFalse("Should not encounter OutOfMemoryError in the fixed version", outOfMemoryErrorThrown);
    }
}

